<?php require_once __DIR__ . '/../includes/header.php'; require_once __DIR__ . '/../includes/csrf.php';
if($_SERVER['REQUEST_METHOD']==='POST'){csrf_check();$pdo->prepare('INSERT INTO meetings(lead_id,meeting_title,meeting_type,meeting_date,meeting_time,meeting_notes,outcome,next_action,assigned_user_id,created_at) VALUES (?,?,?,?,?,?,?,?,?,NOW())')->execute([$_POST['lead_id'],$_POST['meeting_title'],$_POST['meeting_type'],$_POST['meeting_date'],$_POST['meeting_time'],$_POST['meeting_notes'],$_POST['outcome'],$_POST['next_action'],$_POST['assigned_user_id']]);header('Location: /meetings/index.php');exit;}
$meetings=$pdo->query('SELECT m.*,l.full_name lead_name,u.full_name assignee FROM meetings m LEFT JOIN leads l ON l.id=m.lead_id LEFT JOIN users u ON u.id=m.assigned_user_id ORDER BY m.meeting_date ASC,m.meeting_time ASC')->fetchAll();
$leads=$pdo->query('SELECT id,full_name FROM leads WHERE deleted_at IS NULL ORDER BY full_name')->fetchAll();$users=$pdo->query("SELECT id,full_name FROM users WHERE status='Active' AND deleted_at IS NULL ORDER BY full_name")->fetchAll();
?><h3>Meetings</h3><div class="card card-body mb-3"><form method="post" class="row g-2"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><div class="col-md-2"><select class="form-select" name="lead_id"><?php foreach($leads as $l):?><option value="<?= (int)$l['id'] ?>"><?= e($l['full_name']) ?></option><?php endforeach;?></select></div><div class="col-md-2"><input class="form-control" name="meeting_title" placeholder="Title" required></div><div class="col-md-2"><select class="form-select" name="meeting_type"><option>call</option><option>online meeting</option><option>physical meeting</option><option>discussion</option></select></div><div class="col-md-2"><input type="date" class="form-control" name="meeting_date" required></div><div class="col-md-1"><input type="time" class="form-control" name="meeting_time" required></div><div class="col-md-2"><select class="form-select" name="assigned_user_id"><?php foreach($users as $u):?><option value="<?= (int)$u['id'] ?>"><?= e($u['full_name']) ?></option><?php endforeach;?></select></div><div class="col-md-1"><button class="btn btn-primary w-100">Add</button></div><div class="col-md-4"><input class="form-control" name="meeting_notes" placeholder="Notes"></div><div class="col-md-4"><input class="form-control" name="outcome" placeholder="Outcome"></div><div class="col-md-4"><input class="form-control" name="next_action" placeholder="Next action"></div></form></div>
<div class="table-responsive"><table class="table"><thead><tr><th>Title</th><th>Lead</th><th>Type</th><th>Date</th><th>Time</th><th>Outcome</th></tr></thead><tbody><?php foreach($meetings as $m):?><tr><td><?= e($m['meeting_title']) ?></td><td><?= e($m['lead_name']) ?></td><td><?= e($m['meeting_type']) ?></td><td><?= e($m['meeting_date']) ?></td><td><?= e($m['meeting_time']) ?></td><td><?= e($m['outcome']) ?></td></tr><?php endforeach;?></tbody></table></div>
